              <button
                onClick={() => setCurrentStep(4)}
                className="flex-1 px-3 py-2 bg-accent-blue hover:bg-accent-blue-hover text-white rounded-button text-sm font-medium transition-all duration-standard ease-smooth"
              >
                I'm Ready
              </button>
            </div>
          </div>
        );
