/**
 * OnboardingModal Component
 *
 * First-time user onboarding experience
 * - Step 1: Welcome screen with product intro and privacy statement
 * - Step 2: Features tour (Notes, Tasks, Calendar, Time Tracking)
 * - Step 3: Setup (display name, default folder, backup reminder)
 * - Step 4: Completion with CTA to create first note/task
 */

import { useState } from 'react';
import { Modal } from './Modal';
import { useSettingsStore } from '../stores/useSettingsStore';
import { useThemeStore } from '../stores/useThemeStore';
import { isFileSystemAccessSupported } from '../services/brainBackup';
import { BackupOnboardingModal } from './BackupOnboardingModal';
import {
  FileText,
  CheckSquare,
  Calendar,
  Clock,
  Shield,
  Sparkles,
  ArrowRight,
  ArrowLeft,
  X,
  Info
} from 'lucide-react';

interface OnboardingModalProps {
  isOpen: boolean;
  onClose: () => void;
}

export function OnboardingModal({ isOpen, onClose }: OnboardingModalProps) {
  const [currentStep, setCurrentStep] = useState(1);
  const [displayName, setDisplayName] = useState('');
  const [showSkipOptions, setShowSkipOptions] = useState(false);
  const [selectedReminder, setSelectedReminder] = useState<'in-7-days' | 'monthly' | null>(null);
  const [showBackupModal, setShowBackupModal] = useState(false);

  const setOnboardingComplete = useSettingsStore((state) => state.setOnboardingComplete);
  const updateBackupPreferences = useThemeStore((state) => state.updateBackupPreferences);

  const isFSASupported = isFileSystemAccessSupported();

  const totalSteps = 4;

  /**
   * Handle skip tour - mark onboarding complete and close
   */
  const handleSkipTour = () => {
    setOnboardingComplete(true);
    onClose();
  };

  /**
   * Handle completion - save preferences and close
   */
  const handleComplete = () => {
    setOnboardingComplete(true);
    onClose();
  };

  /**
   * Navigate to next step
   */
  const handleNext = () => {
    if (currentStep < totalSteps) {
      setCurrentStep(currentStep + 1);
    }
  };

  /**
   * Navigate to previous step
   */
  const handleBack = () => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  };

  /**
   * Open backup setup modal
   */
  const handleSetupBackup = () => {
    setShowBackupModal(true);
  };

  /**
   * Handle backup modal completion
   */
  const handleBackupComplete = () => {
    setShowBackupModal(false);
    handleComplete();
  };

  /**
   * Handle skip with reminder preference
   */
  const handleSkipWithReminder = () => {
    if (selectedReminder) {
      const nextReminderDate =
        selectedReminder === 'in-7-days'
          ? new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString()
          : new Date(new Date().getFullYear(), new Date().getMonth() + 1, 1).toISOString();

      updateBackupPreferences({
        reminderPreference: selectedReminder,
        nextReminderDate,
      });
    }
    handleComplete();
  };

  /**
   * Handle skip forever (never remind)
   */
  const handleSkipForever = () => {
    updateBackupPreferences({
      reminderPreference: 'never',
      nextReminderDate: null,
    });
    handleComplete();
  };

  /**
   * Step 1: Welcome
   */
  const renderWelcomeStep = () => (
    <div className="space-y-6">
      <div className="text-center">
        <div className="flex items-center justify-center mb-4">
          <Sparkles className="h-12 w-12 text-primary-magenta" />
        </div>
        <h2 className="text-2xl font-bold text-text-light-primary dark:text-text-dark-primary mb-2">
          Welcome to Neuman Brain
        </h2>
        <p className="text-text-light-secondary dark:text-text-dark-secondary">
          Your privacy-first productivity platform
        </p>
      </div>

      <div className="bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg p-6 space-y-4">
        <div className="flex items-start gap-3">
          <Shield className="h-6 w-6 text-primary-cyan shrink-0 mt-1" />
          <div>
            <h3 className="font-semibold text-text-light-primary dark:text-text-dark-primary mb-1">
              Privacy by Design
            </h3>
            <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
              All your data stays on your device. No servers, no tracking, no third parties.
              Your information never leaves your computer unless you choose to export it.
            </p>
          </div>
        </div>

        <div className="flex items-start gap-3">
          <FileText className="h-6 w-6 text-primary-magenta shrink-0 mt-1" />
          <div>
            <h3 className="font-semibold text-text-light-primary dark:text-text-dark-primary mb-1">
              All-in-One Platform
            </h3>
            <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
              Notes, tasks, calendar, time tracking, and more - unified in one place.
              No more juggling multiple apps and subscriptions.
            </p>
          </div>
        </div>
      </div>
    </div>
  );

  /**
   * Step 2: Features Tour
   */
  const renderFeaturesTourStep = () => (
    <div className="space-y-6">
      <div className="text-center">
        <h2 className="text-2xl font-bold text-text-light-primary dark:text-text-dark-primary mb-2">
          Your Productivity Toolkit
        </h2>
        <p className="text-text-light-secondary dark:text-text-dark-secondary">
          Everything you need to stay organized and focused
        </p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <div className="bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg p-4">
          <div className="flex items-center gap-2 mb-2">
            <FileText className="h-5 w-5 text-primary-magenta" />
            <h3 className="font-semibold text-text-light-primary dark:text-text-dark-primary">
              Notes
            </h3>
          </div>
          <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
            Rich text editor with wiki links, backlinks, folders, and powerful search
          </p>
        </div>

        <div className="bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg p-4">
          <div className="flex items-center gap-2 mb-2">
            <CheckSquare className="h-5 w-5 text-primary-cyan" />
            <h3 className="font-semibold text-text-light-primary dark:text-text-dark-primary">
              Tasks
            </h3>
          </div>
          <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
            Kanban boards, Gantt charts, subtasks, and recurring tasks for project management
          </p>
        </div>

        <div className="bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg p-4">
          <div className="flex items-center gap-2 mb-2">
            <Calendar className="h-5 w-5 text-primary-purple" />
            <h3 className="font-semibold text-text-light-primary dark:text-text-dark-primary">
              Calendar
            </h3>
          </div>
          <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
            Schedule events, import ICS files, and integrate with your task list
          </p>
        </div>

        <div className="bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg p-4">
          <div className="flex items-center gap-2 mb-2">
            <Clock className="h-5 w-5 text-primary-magenta" />
            <h3 className="font-semibold text-text-light-primary dark:text-text-dark-primary">
              Time Tracking
            </h3>
          </div>
          <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
            Track work hours, manage projects, and analyze productivity patterns
          </p>
        </div>
      </div>
    </div>
  );

  /**
   * Step 3: Setup
   */
  const renderSetupStep = () => (
    <div className="space-y-6">
      <div className="text-center">
        <h2 className="text-2xl font-bold text-text-light-primary dark:text-text-dark-primary mb-2">
          Quick Setup
        </h2>
        <p className="text-text-light-secondary dark:text-text-dark-secondary">
          Personalize your experience (optional)
        </p>
      </div>

      <div className="space-y-4">
        <div>
          <label
            htmlFor="display-name"
            className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-2"
          >
            Display Name (Optional)
          </label>
          <input
            id="display-name"
            type="text"
            value={displayName}
            onChange={(e) => setDisplayName(e.target.value)}
            placeholder="Enter your name"
            className="w-full px-3 py-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-text-light-primary dark:text-text-dark-primary placeholder:text-text-light-disabled dark:placeholder:text-text-dark-disabled focus:outline-none focus:ring-2 focus:ring-primary-cyan"
          />
          <p className="mt-1 text-xs text-text-light-secondary dark:text-text-dark-secondary">
            This is just for you - it won't be shared with anyone
          </p>
        </div>

        <div className="bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg p-4">
          <div className="flex items-start gap-3">
            <Shield className="h-5 w-5 text-primary-cyan shrink-0 mt-0.5" />
            <div className="flex-1">
              <h3 className="font-semibold text-text-light-primary dark:text-text-dark-primary mb-1">
                Backup Reminder
              </h3>
              <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary mb-3">
                Your data is stored in your browser. Regular backups ensure you never lose your work.
              </p>
              <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
                You can set up automatic backups anytime in Settings → Backup & Sync
              </p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );

  /**
   * Step 4: Completion
   */
  const renderCompletionStep = () => (
    <div className="space-y-6">
      <div className="text-center">
        <div className="flex items-center justify-center mb-4">
          <Sparkles className="h-12 w-12 text-primary-magenta" />
        </div>
        <h2 className="text-2xl font-bold text-text-light-primary dark:text-text-dark-primary mb-2">
          You're All Set!
        </h2>
        <p className="text-text-light-secondary dark:text-text-dark-secondary">
          Ready to start organizing your life
        </p>
      </div>

      <div className="bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg p-6 space-y-4">
        <h3 className="font-semibold text-text-light-primary dark:text-text-dark-primary text-center mb-4">
          Get Started
        </h3>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
          <button
            onClick={handleComplete}
            className="flex items-center justify-center gap-2 px-4 py-3 bg-primary-magenta text-white rounded-lg hover:bg-primary-magenta/90 transition-colors"
          >
            <FileText className="h-4 w-4" />
            <span className="font-medium">Create Your First Note</span>
          </button>

          <button
            onClick={handleComplete}
            className="flex items-center justify-center gap-2 px-4 py-3 bg-primary-cyan text-white rounded-lg hover:bg-primary-cyan/90 transition-colors"
          >
            <CheckSquare className="h-4 w-4" />
            <span className="font-medium">Create Your First Task</span>
          </button>
        </div>

        <p className="text-xs text-center text-text-light-secondary dark:text-text-dark-secondary">
          You can access all features from the sidebar on the left
        </p>
      </div>
    </div>
  );

  /**
   * Render current step content
   */
  const renderStepContent = () => {
    switch (currentStep) {
      case 1:
        return renderWelcomeStep();
      case 2:
        return renderFeaturesTourStep();
      case 3:
        return renderSetupStep();
      case 4:
        return renderCompletionStep();
      default:
        return null;
    }
  };

  return (
    <Modal isOpen={isOpen} onClose={onClose} title="Welcome to Neuman Brain" maxWidth="lg">
      <div className="relative">
        {/* Skip button */}
        <button
          onClick={handleSkipTour}
          className="absolute top-0 right-0 p-2 text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary transition-colors"
          aria-label="Skip tour"
        >
          <X className="h-5 w-5" />
        </button>

        {/* Progress indicator */}
        <div className="flex items-center justify-center gap-2 mb-6">
          {Array.from({ length: totalSteps }).map((_, index) => (
            <div
              key={index}
              className={`h-2 w-12 rounded-full transition-colors ${
                index + 1 === currentStep
                  ? 'bg-primary-magenta'
                  : index + 1 < currentStep
                  ? 'bg-primary-cyan'
                  : 'bg-border-light dark:bg-border-dark'
              }`}
            />
          ))}
        </div>

        {/* Step content */}
        <div className="min-h-[400px]">
          {renderStepContent()}
        </div>

        {/* Navigation buttons */}
        {currentStep < totalSteps && (
          <div className="flex items-center justify-between mt-8 pt-6 border-t border-border-light dark:border-border-dark">
            <button
              onClick={handleBack}
              disabled={currentStep === 1}
              className="flex items-center gap-2 px-4 py-2 text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
            >
              <ArrowLeft className="h-4 w-4" />
              <span>Back</span>
            </button>

            <button
              onClick={handleSkipTour}
              className="text-sm text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary transition-colors"
            >
              Skip tour
            </button>

            <button
              onClick={handleNext}
              className="flex items-center gap-2 px-6 py-2 bg-primary-magenta text-white rounded-lg hover:bg-primary-magenta/90 transition-colors"
            >
              <span>Next</span>
              <ArrowRight className="h-4 w-4" />
            </button>
          </div>
        )}
      </div>
    </Modal>
  );
}
